-- 6. Maidstone × Social Media Setup
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'social-media-setup',
  'maidstone',
  'Social media is where Maidstone residents discover, research, and recommend local businesses. From Facebook community groups covering Bearsted and Loose to Instagram accounts showcasing work across the county town, your social presence is often the first interaction a potential customer has with your brand. Yet most Maidstone businesses either have no social media at all, or maintain dormant profiles with outdated information and no engagement strategy. We set up professional, optimised social media profiles for Maidstone businesses, complete with branded visuals, local content strategies, and the foundations needed to generate genuine engagement and enquiries from the county-town market.',
  'Maidstone has an active local social media ecosystem. Facebook groups like Maidstone Community, Maidstone Chat, and village-specific groups for Bearsted, Loose, and Barming have thousands of engaged members recommending businesses daily. Instagram is increasingly used by trades to showcase completed projects across the borough. LinkedIn is essential for professional services firms near County Hall and King Street. The Lockmeadow and Fremlin Walk areas generate significant social media check-ins and location-tagged content.',
  'Social media adoption among Maidstone businesses is patchy. Some trades have built strong followings through project showcases, while most professional services have a LinkedIn page with no activity. The businesses gaining most traction are those posting consistently with local context, tagging Maidstone locations, and engaging with community groups. The opportunity for businesses willing to maintain a professional, active presence is significant.',
  'We set up each platform specifically for the Maidstone market. That means optimising profiles for local search discovery, creating content calendars built around Maidstone events and seasonal patterns, and connecting your social presence to your website for seamless lead capture. We do not just create accounts and hand them over: we build the complete system you need to maintain momentum.',
  '{"population": 113137, "business_count": "4500+", "key_areas": ["Town Centre", "Fremlin Walk", "Bearsted", "Loose", "Barming", "Lockmeadow"]}',
  '[{"title": "No social media presence in a market where recommendations are digital", "description": "When a Maidstone resident asks for a recommendation in a local Facebook group, they immediately check the suggested business''s social profiles. Businesses without a professional, active presence are dismissed as outdated or unreliable, regardless of their actual service quality."}, {"title": "Dormant profiles damaging first impressions", "description": "A Facebook page that has not been updated since 2022 or an Instagram account with three posts sends a clear signal to Maidstone customers: this business is not active or does not care about its image. Dormant profiles are worse than no profiles at all."}, {"title": "No strategy connecting social media to actual enquiries", "description": "Even Maidstone businesses with decent social followings often have no clear path from a social media post to a paying customer. Likes and comments feel good but generate zero revenue without a deliberate lead capture strategy built into the social media framework."}]',
  '[{"title": "Professional Maidstone-optimised profile setup", "description": "We create and fully optimise your business profiles across Facebook, Instagram, LinkedIn, and Google Business Profile. Every profile is branded consistently, populated with Maidstone-specific information, and configured for local search discovery so customers in the county town find you easily."}, {"title": "Local content strategy and calendar", "description": "We build a content calendar tailored to the Maidstone market, incorporating local events, seasonal trends, and community engagement opportunities. You receive templates, post ideas, and a clear schedule so maintaining your social presence takes minutes rather than hours each week."}, {"title": "Social-to-website lead capture integration", "description": "We connect your social media profiles to your website''s lead capture system so that engagement converts to enquiries. Call-to-action buttons, link-in-bio pages, and promoted post strategies are all configured to drive Maidstone followers toward becoming customers."}]',
  '[{"question": "Which social media platforms should a Maidstone business use?", "answer": "It depends on your market. Trades in Maidstone get the most traction from Facebook and Instagram, where project photos and community group engagement drive recommendations. Professional services benefit most from LinkedIn and Google Business Profile. We assess your specific Maidstone market and recommend the right combination."}, {"question": "How often should I post on social media?", "answer": "For Maidstone businesses, we recommend a minimum of three posts per week across your primary platforms. Consistency matters more than volume. Our content calendar makes this manageable by providing templates and scheduling tools tailored to the Maidstone market."}, {"question": "Can you manage my social media for me ongoing?", "answer": "Our core service is the professional setup, strategy, and training to empower you to manage your own profiles. However, we do offer ongoing management packages for Maidstone businesses that prefer a fully hands-off approach. We can discuss this during your initial consultation."}, {"question": "Should I be posting in Maidstone community Facebook groups?", "answer": "Yes, but carefully. Maidstone community groups are powerful for local businesses, but they have strict rules about self-promotion. We train you on how to engage authentically, offer value, and build your reputation within these groups without triggering admin warnings or appearing spammy."}]',
  'trust'
)
